        foreach ($tc in @($suite.testcase)) {
            if (-not $tc) { continue }
            $status  = 'passed'
            $message = $null
            if ($tc.failure) { $status = 'failed';  $message = [string]$tc.failure.message }
            elseif ($tc.error)   { $status = 'failed';  $message = [string]$tc.error.message }
            elseif ($tc.skipped) { $status = 'skipped' }
