                ClassName = [string]$tc.classname
                Name      = [string]$tc.name
                Status    = $status
                Duration  = if ($tc.time) { [double]$tc.time } else { 0.0 }
                Message   = $message
            })
        }
    }

    [pscustomobject]@{
        Suite    = $name
        Source   = $resolved
        Duration = $duration
        Tests    = $tests.ToArray()
    }
}

function Read-JsonTestResults {
    [CmdletBinding()]
