            }
        }
    }

    [pscustomobject]@{
        RunCount = @($Results).Count
        Totals   = [pscustomobject]@{
            Passed   = $passed
            Failed   = $failed
            Skipped  = $skipped
            Total    = $passed + $failed + $skipped
            Duration = [math]::Round($duration, 3)
        }
        Flaky    = @($flaky)
        Failures = @($failures)
    }
