    foreach ($suite in $suites) {
        if (-not $suite) { continue }
        if (-not $name)  { $name = [string]$suite.GetAttribute('name') }
        $timeAttr = $suite.GetAttribute('time')
        if ($timeAttr) { $duration += [double]$timeAttr }

